const PROCESSING_FEE = 5;
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

export function claimOffice(request: any): any {
  const items = request.steps[0].items;

  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
    }
  }

  let basePremium = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type) && componentCounts[item.type] === BLOCK_SIZE) {
      continue;
    }
    basePremium += BASE_PREMIUMS[item.type];
  }

  for (const type of Object.keys(componentCounts)) {
    if (componentCounts[type] === BLOCK_SIZE) {
      basePremium += BLOCK_PREMIUM;
    }
  }

  return [{ premium: basePremium + PROCESSING_FEE }];
}

